import os
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.common.keys import Keys
from PIL import Image
import boto3
from botocore.exceptions import NoCredentialsError

class ScreenshotService:
    def __init__(self):
        self.s3 = boto3.client('s3')
        self.chrome_options = Options()
        self.chrome_options.add_argument('--headless')
        self.driver = webdriver.Chrome(options=self.chrome_options)

    def take_screenshot(self, url):
        try:
            self.driver.get(url)
            width = 800
            height = 600
            self.driver.set_window_size(width, height)
            screenshot = self.driver.get_screenshot_as_png()
            return screenshot
        except Exception as e:
            print(f"Failed to take screenshot: {e}")
            return None

    def save_to_s3(self, screenshot, url):
        try:
            s3_object_key = f"screenshots/{url}.png"
            self.s3.put_object(Body=screenshot, Bucket='your-bucket-name', Key=s3_object_key)
            print(f"Screenshot saved to S3: {s3_object_key}")
            return s3_object_key
        except NoCredentialsError:
            print("No AWS credentials found")
            return None

    def resize_screenshot(self, url):
        try:
            screenshot = self.s3.get_object(Bucket='your-bucket-name', Key=f"screenshots/{url}.png")['Body']
            image = Image.open(BytesIO(screenshot.read()))
            width, height = 200, 150
            image.thumbnail((width, height))
            resized_screenshot = BytesIO()
            image.save(resized_screenshot, format='PNG')
            return resized_screenshot.getvalue()
        except Exception as e:
            print(f"Failed to resize screenshot: {e}")
            return None

    def run(self):
        url = 'https://www.example.com'
        screenshot = self.take_screenshot(url)
        s3_object_key = self.save_to_s3(screenshot, url)
        resized_screenshot = self.resize_screenshot(url)

if __name__ == "__main__":
    service = ScreenshotService()
    service.run()